#include <bits/stdc++.h>
using namespace std;
const int N=100005;
long long n,k,a[N],s[N],s2[N],tr[N],mn=0x3f3f3f3f,mx=0;
long long ans=0;
map<long long,int> mp;
void add(long long now)
{
	while(now<=n)
    {
		tr[now]++;
		now+=(now&(-now));
	}
}
int sum(long long now)
{
	long long sum2=0;
	while(now)
    {
		sum2+=tr[now];
		now-=(now&(-now));
	}
	return sum2;
}
int main()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i]-=k;
        s[i]=s[i-1]+a[i];
        s2[i]=s[i];
        mn=min(mn,s[i]);
    }
    s[++n]=0;
    sort(s+1,s+1+n);
    int len=unique(s+1,s+n+1)-s-1;
    for(int i=1;i<=len;i++)
    {
        mp[s[i]]=i;
    }
    add(mp[0]);
    n--;
    for(int i=1;i<=n;i++)
    {
        s[i]=mp[s2[i]];
    }
    for(int i=1;i<=n;i++)
    {
        ans+=sum(s[i]);
        add(s[i]);
    }
    cout<<ans;
    return 0;
 }
